];

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const fetchQuestion = async (level: number, lang: Language, attempt = 0): Promise<Question> => {
  const modelName = level === 15 ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const difficultyMap = {
    low: "straightforward but professional",
    mid: "moderately challenging",
    high: "difficult, focusing on specific details",
    expert: "extremely obscure historical or scientific facts"
  };

  let difficultyTier = "low";
  if (level > 4) difficultyTier = "mid";
  if (level > 9) difficultyTier = "high";
  if (level > 13) difficultyTier = "expert";

  const languageName = lang === Language.HINDI ? "Hindi" : "English";
  const category = CATEGORIES[Math.floor(Math.random() * CATEGORIES.length)];
  const randomFactor = Math.random().toString(36).substring(7);

  const prompt = `Act as an expert KBC quiz master. Create one unique, factually accurate multiple-choice question.
  CATEGORY: ${category}
  LEVEL: ${level}/15
  TONE: ${difficultyMap[difficultyTier as keyof typeof difficultyMap]}
  LANGUAGE: ${languageName}
  UNIQUE_SEED: ${randomFactor}

  CRITICAL RULES:
  - Respond with a SINGLE JSON OBJECT ONLY.
  - The question MUST be 100% factually accurate.
  - Explanation should be insightful and provide context.`;

  try {
    const config: any = {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          text: { type: Type.STRING },
          options: {
            type: Type.OBJECT,
            properties: {
              A: { type: Type.STRING },
              B: { type: Type.STRING },
              C: { type: Type.STRING },
              D: { type: Type.STRING }
            },
            required: ["A", "B", "C", "D"]
          },
          correctAnswer: { type: Type.STRING, enum: ["A", "B", "C", "D"] },
          explanation: { type: Type.STRING }
        },
        required: ["text", "options", "correctAnswer", "explanation"]
      }
    };

    if (level >= 10) {
      config.thinkingConfig = { thinkingBudget: 2000 };
    }
    if (level === 15) {
      config.thinkingConfig = { thinkingBudget: 12000 };
    }

    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
      config: config
    });

    const text = response.text || "{}";
    const data = JSON.parse(text);

    if (!data.text || !data.options || !data.correctAnswer) {
      throw new Error("Malformed JSON response");
    }

    return data as Question;
  } catch (error: any) {
    console.warn(`[Gemini API] Level ${level} Attempt ${attempt + 1} Error:`, error?.message || error);

    if (attempt < 4) {
      const waitTime = Math.pow(2, attempt) * 1000 + Math.random() * 1000;
      await sleep(waitTime);
      return fetchQuestion(level, lang, attempt + 1);
    }

    const fallbacks: Record<Language, Question> = {
      [Language.HINDI]: {
        text: "इनमें से कौन सा शहर 'गुलाबी शहर' (Pink City) के रूप में जाना जाता है?",
        options: {
          A: "जोधपुर",
          B: "जयपुर",
          C: "उदयपुर",
          D: "बीकानेर"
        },
        correctAnswer: "B",
        explanation: "जयपुर को अपनी विशिष्ट गुलाबी रंग की इमारतों के कारण 'गुलाबी शहर' कहा जाता है।"
      },
      [Language.ENGLISH]: {
        text: "Which of these cities is famously known as the 'Pink City' of India?",
        options: {
          A: "Jodhpur",
          B: "Jaipur",
          C: "Udaipur",
          D: "Bikaner"
        },
        correctAnswer: "B",
        explanation: "Jaipur is called the Pink City because of the dominant color scheme of its buildings."
      }
    };

    return fallbacks[lang];
  }
};

